THOUGHT: The crash happens because GVN’s propagateEquality replaces the alloca pointer with null after an assume, and the replacement flows into llvm.lifetime.start/end operands, which must be alloca or poison. In GVN.cpp, propagateEquality uses replaceDominatedUsesWithIf with a CanReplacePointersCallBack predicate to control pointer replacements. I will inspect where this callback is defined and modify it to return false for uses that are the pointer operands of llvm.lifetime.start/end intrinsics, preventing such replacements. Then I will run the test reproducer with opt -passes=gvn to verify the fix and submit the patch.

```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Scalar/GVN.cpp
@@
   auto CanReplacePointersCallBack = [&](Use &U) {
     // We can replace pointers with other pointers, unless doing so would in turn
     // require replacing the loads/stores that these pointers feed.  These
     // instructions may have alias analysis metadata which depends on the pointer
     // operand, and we don't know how to update it.  See PRs 9841 and 9862.
+    // Additionally, do not substitute the pointer operand of lifetime intrinsics.
+    // The verifier requires llvm.lifetime.start/end to operate on an alloca or poison.
+    // If we propagate an equality from an assume (e.g., %alloca == null) and replace
+    // the lifetime pointer with null, we break the verifier. Prevent replacing the
+    // pointer operand of lifetime.start/end intrinsics here.
     Instruction *I = dyn_cast<Instruction>(U.getUser());
     if (!I)
       return true;
+    if (auto *II = dyn_cast<IntrinsicInst>(I)) {
+      Intrinsic::ID ID = II->getIntrinsicID();
+      if (ID == Intrinsic::lifetime_start || ID == Intrinsic::lifetime_end) {
+        // Operand 1 is the pointer argument for lifetime intrinsics.
+        if (U.getOperandNo() == 1)
+          return false;
+      }
+    }
     if (isa<LoadInst>(I) || isa<StoreInst>(I))
       return false;
     return true;
   };
*** End Patch
EOF
```

